/**
 * @summary Initiate a payment for a job (Stripe or Paystack)
 */
export const InitiatePaymentParams = zod.object({
  tenantId: zod.coerce.number(),
});

export const InitiatePaymentBody = zod.object({
  jobId: zod.number(),
  amount: zod.number(),
  customerEmail: zod.string(),
  customerName: zod.string(),
});

export const InitiatePaymentResponse = zod.object({
  provider: zod.string(),
  checkoutUrl: zod.string().nullable(),
  reference: zod.string(),
  clientSecret: zod.string().nullable(),
});

/**
 * @summary Verify a payment
 */
export const VerifyPaymentParams = zod.object({
  tenantId: zod.coerce.number(),
});

export const VerifyPaymentBody = zod.object({
  jobId: zod.number(),
  reference: zod.string(),
  provider: zod.string(),
});

export const VerifyPaymentResponse = zod.object({
  success: zod.boolean(),
  status: zod.string(),
  jobId: zod.number(),
});
